example.code:
# /etc/nginx/snippets/ssl-params.conf
ssl_protocols             TLSv1.2 TLSv1.3;
ssl_ciphers               ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256:ECDHE-ECDSA-AES256-GCM-SHA384:ECDHE-RSA-AES256-GCM-SHA384;
ssl_prefer_server_ciphers off;   # Let client choose for TLS 1.3

ssl_session_timeout 1d;
ssl_session_cache   shared:SSL:10m;   # ~40,000 sessions
ssl_session_tickets off;              # Disable for forward secrecy

# DH params for TLS 1.2 DHE ciphers (generate once)
# ssl_dhparam /etc/nginx/dhparam.pem;

# OCSP — only with Let's Encrypt or commercial certs; NOT Cloudflare origin certs
# ssl_stapling        on;
# ssl_stapling_verify on;
# resolver 1.1.1.1 8.8.8.8 valid=300s;
# resolver_timeout 5s;

server {
    listen 80;
    server_name example.com;

    # Allow certbot HTTP challenge
    location /.well-known/acme-challenge/ {
        root /var/www/html;
    }

    location / {
        return 301 https://$host$request_uri;
    }
}
